// ─── Main Client Component ───────────────────────────────────────────────────

export function QuoteReviewClient({ quote }: { quote: QuoteData }) {
  const [accepted, setAccepted] = useState(quote.status === "accepted");
  const [isAccepting, setIsAccepting] = useState(false);
  const [isPayingEMI, setIsPayingEMI] = useState(false);
  const [cashfree, setCashfree] = useState<Cashfree | null>(null);

  useEffect(() => {
    const initCashfree = async () => {
      try {
        const cf = await load({ mode: "sandbox" }); // Change to "production" when live
        setCashfree(cf);
      } catch (err) {
        console.error("Failed to load Cashfree SDK", err);
      }
    };
    initCashfree();
  }, []);

  const handlePayEMI = async () => {
    if (!cashfree) {
      toast.error("Payment system not ready. Please refresh.");
      return;
    }

    setIsPayingEMI(true);
    try {
      const res = await fetch(`/api/quotes/${quote.id}/accept`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ leadId: quote.leadId, paymentMethod: "emi" }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Failed to initiate EMI payment");

      const checkoutOptions = {
        paymentSessionId: data.payment_session_id,
        redirectTarget: "_self" as const,
      };

      await cashfree.checkout(checkoutOptions);
    } catch (err: any) {
      toast.error(err.message);
      console.error(err);
    } finally {
      setIsPayingEMI(false);
    }
  };

  const subtotal = quote.lineItems.reduce((s, i) => s + i.quantity * i.unitPrice, 0);
  const halfGst  = (subtotal * quote.gstPercent) / 200;
  const total    = subtotal + halfGst * 2;
  const advance  = Math.round(total * quote.advancePercent / 100);
  const daysLeft = daysUntil(quote.validUntil);

  const NAVY  = "#0F1F3D";
  const GOLD  = "#C8922A";

  async function handleAccept() {
    setIsAccepting(true);
    try {
      await updateDoc(
        doc(db, "leads", quote.leadId, "quotes", quote.id),
        {
          status: "accepted",
          accepted_at: serverTimestamp(),
          accepted_by_uid: auth.currentUser?.uid || "anonymous",
        }
      );
      setAccepted(true);
      toast.success("Quote accepted successfully! We will contact you soon.");
    } catch (err) {
      console.error(err);
      toast.error("Could not save your acceptance. Please try again.");
    } finally {
      setIsAccepting(false);
    }
  }

  const handleDownloadPDF = async () => {
    try {
      toast.info("Generating your PDF...");
      const pdfRes = await fetch(`/api/v1/leads/${quote.leadId}/quotes/${quote.id}/pdf`);
      if (pdfRes.ok) {
        const contentType = pdfRes.headers.get("Content-Type");
        if (contentType === "application/pdf") {
          const blob = await pdfRes.blob();
          const blobUrl = URL.createObjectURL(blob);
          window.open(blobUrl, "_blank");
        } else {
          const { url } = await pdfRes.json();
          if (url) {
            window.open(url, "_blank");
          }
        }
      } else {
         toast.error("Failed to generate PDF.");
      }
    } catch (error) {
      console.error("PDF download failed", error);
      toast.error("An error occurred while downloading the PDF.");
    }
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "#FAFAF7",
        fontFamily: "'DM Sans', system-ui, sans-serif",
        padding: "24px 16px 80px",
      }}
    >
      <div style={{ maxWidth: 860, margin: "0 auto" }}>

        {/* ── Status bar ─────────────────────────────────────────────── */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 20, flexWrap: "wrap", gap: 8 }}>
          <StatusPill status={accepted ? "accepted" : quote.status} />
          {!accepted && (
            <span
              style={{
                fontSize: 12,
                color: "#6B7380",
                background: "white",
                border: "1px solid #E4E4DC",
                padding: "5px 12px",
                borderRadius: 100,
                display: "flex",
                alignItems: "center",
                gap: 5,
              }}
            >
              ⏱ Valid until {formatDate(quote.validUntil)}
              {daysLeft > 0 && (
                <strong style={{ color: daysLeft <= 3 ? "#C0392B" : "#A05F00" }}>
                  &nbsp;· {daysLeft}d left
                </strong>
              )}
              {daysLeft === 0 && <strong style={{ color: "#C0392B" }}>&nbsp;· Expires today</strong>}
            </span>
          )}
        </div>

        {/* ── Main card ─────────────────────────────────────────────── */}
        <div
          style={{
            background: "white",
            borderRadius: 10,
            boxShadow: "0 12px 40px rgba(15,31,61,.13)",
            overflow: "hidden",
            border: "1px solid rgba(228,228,220,.6)",
          }}
        >

          {/* ── Header ──────────────────────────────────────────────── */}
          <div
            style={{
              background: NAVY,
              padding: "32px 36px 28px",
              position: "relative",
              overflow: "hidden",
            }}
          >
