          </div>

        </div>{/* /card */}
      </div>
    </div>
  );
}

import { NextRequest } from "next/server";
import { adminDb, serverTimestamp } from "@/lib/firebase-admin";
import { rateLimit } from "@/lib/rate-limit";
import { calculatePricing } from "@/lib/pricing-engine";
import { SETTINGS_DOC_ID } from "@/lib/firebase-client";
import { GenerateQuoteSchema } from "@/lib/validators";
import { Product, Addon, AppSettings, Lead } from "@/types";
import { createAuditLog, getRequestMetadata } from "@/lib/audit-logs";
import { ApiResponse } from "@/lib/api-response";

/** 
 * ENTERPRISE-GRADE QUOTE PERSISTENCE
 * Implements Zero-Trust Price Validation by recalculating all costs on the server.
 */
export async function POST(request: NextRequest) {
  const { success } = await rateLimit(request);
  if (!success) {
    return ApiResponse.error("Too many requests", "RATE_LIMIT_EXCEEDED", 429);
  }

  try {
    const body = await request.json();

    // 1. Validate Input Structure
    const validation = GenerateQuoteSchema.safeParse(body.selection);
    if (!validation.success) {
      console.error("ZOD VALIDATION FAILED", JSON.stringify(validation.error.format(), null, 2));
      return ApiResponse.badRequest("Invalid selection payload", validation.error.format());
    }

    const { lead_id, firebase_uid, address, status, accepted_at } = body;
    const selection = validation.data;

    if (!lead_id) {
      return ApiResponse.badRequest("Missing lead_id");
    }

    if (!adminDb) {

       return ApiResponse.error("Database not initialized", "INTERNAL_ERROR", 500);
    }

    // 2. Fetch Authoritative Data (Server-Side Source of Truth)
    const [leadDoc, productsSnap, addonsSnap, settingsSnap, geoRulesSnap] = await Promise.all([
      adminDb.collection("leads").doc(lead_id).get(),
      adminDb.collection("products").where("is_active", "==", true).where("is_deleted", "==", false).get(),
      adminDb.collection("addons").where("is_active", "==", true).where("is_deleted", "==", false).get(),
      adminDb.collection("settings").doc(SETTINGS_DOC_ID).get(),
      adminDb.collection("geo_pricing_rules").where("is_active", "==", true).get()
    ]);

    if (!leadDoc.exists) {
      return ApiResponse.error("Lead not found", "NOT_FOUND", 404);
    }

    const leadData = leadDoc.data() as Lead;

    // Ownership verification
    if (firebase_uid && leadData.firebase_uid !== firebase_uid) {
      return ApiResponse.forbidden("Forbidden: Lead ownership mismatch");
    }

    let products = productsSnap.docs.map(d => ({ id: d.id, ...d.data() })) as Product[];
    let addons = addonsSnap.docs.map(d => ({ id: d.id, ...d.data() })) as Addon[];
    let geoRules = geoRulesSnap.docs.map(d => ({ id: d.id, ...d.data() })) as any[];


    const settings = settingsSnap.data() as AppSettings;

    // 3. SERVER-SIDE PRICE RECALCULATION (IMMUTABLE BY CLIENT)
    const pricing = calculatePricing({
      selection: selection as any, // Cast to any to bypass strict null checking from Zod schema vs internal type
      products,
      addons,
      settings,
      cablingDone: leadData.cabling_done || false,
      referralDiscountPercent: 0, // Injected via promoter lookup if needed
      referralDiscountFlat: 0,
      activeOffer: leadData.active_offer,
      geoRules,
      locationParams: {
        pincode: leadData.address?.pincode
      }
    });

    // 3.5 ZERO-TRUST VALIDATION
    if (selection.expected_total_payable !== undefined && selection.expected_total_payable !== null) {
      // Allow up to ₹1 difference for potential floating-point rounding mismatches
      if (Math.abs(pricing.total_payable - selection.expected_total_payable) > 1) {
        console.error(`[Zero-Trust Validation] Price mismatch detected for lead ${lead_id}. Backend calculated: ${pricing.total_payable}, Frontend expected: ${selection.expected_total_payable}`);
        console.error("Backend Pricing Snapshot:", JSON.stringify(pricing, null, 2));
        console.error("Backend Products Count:", products.length, "Backend Addons Count:", addons.length);
        console.error("Selection received:", JSON.stringify(selection, null, 2));
        return ApiResponse.error(
          "Price mismatch. Pricing has been updated since you loaded the page. Please refresh to see the latest prices.",
          "PRICE_TAMPERING_OR_STALE",
          400
        );
      }
    }

    const cleanPricing = JSON.parse(JSON.stringify(pricing));

    // 4. PERSIST QUOTE TO DATABASE
    const quoteRef = adminDb.collection("leads").doc(lead_id).collection("quotes").doc();

    const quotePromise = quoteRef.set({
      ...cleanPricing,
      plan_type: selection.plan_type,
      technology: selection.technology,
      configuration_snapshot: cleanPricing.items, 
      addons_snapshot: cleanPricing.addons,
      expected_total_payable: selection.expected_total_payable || cleanPricing.total_payable,
      status: status || "draft",
      accepted_at: accepted_at ? new Date(accepted_at) : null,
      created_at: new Date().toISOString(),
      expires_at: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(),
      recalculated_on_server: true,
    });

    // 5. Update Lead Status
    const updatePayload: Record<string, any> = { 
      status: status === "accepted" ? "accepted" : "quoted",
      last_quote_id: quoteRef.id,
      updated_at: serverTimestamp()
    };
    if (address) updatePayload.address = address;

    const leadPromise = adminDb.collection("leads").doc(lead_id).update(updatePayload);

    await Promise.all([quotePromise, leadPromise]);

    // 6. Enterprise Audit Logging
    const { ip, ua } = getRequestMetadata(request);
    await createAuditLog({
      action: status === "accepted" ? "QUOTE_ACCEPT" : "QUOTE_RECALCULATE",
      actor_id: firebase_uid || "guest",
      resource_id: quoteRef.id,
      resource_type: "quote",
      ip_address: ip,
      user_agent: ua,
      metadata: {
        total_payable: pricing.total_payable,
        plan_type: selection.plan_type,
        lead_id
      }
    });

    return ApiResponse.success({ 
      id: quoteRef.id, 
      message: "Quote recalculated and saved successfully",
      total_payable: pricing.total_payable 
    }, 201);

  } catch (error: any) {
    console.error("Critical error in quote persistence:", error);
    return ApiResponse.error("Internal server error", "INTERNAL_ERROR", 500, error.message);
  }
}

"use client";

import { useRef, useState, useCallback } from "react";
import Papa from "papaparse";
import { toast } from "sonner";
import {
  Upload,
  Download,
  FileText,
  X,
  CheckCircle2,
  AlertCircle,
  Loader2,
  Filter,
  ChevronDown,
  FileDown,
  FilePlus2,
  RefreshCcw,
  ArrowRight,
} from "lucide-react";

// ─── Types ───────────────────────────────────────────────────────────────────

interface ParsedRow {
  id?: string;
  technical_name?: string;
  display_name?: string;
  category?: string;
  technology?: string;
  brand?: string;
  base_cost?: string | number;
  margin_percentage?: string | number;
  unit_price?: string | number;
  unit_price_budget?: string | number;
  unit_price_premium?: string | number;
  resolution_mp?: string | number;
  channels?: string | number;
  max_cameras?: string | number;
  min_cameras?: string | number;
  catalog_path?: string;
  is_active?: string | boolean;
  image_url?: string;
  [key: string]: unknown;
}

interface RowError {
  row: number;
  field: string;
  message: string;
}

interface PreviewResult {
  toCreate: ParsedRow[];
  toUpdate: ParsedRow[];
  errors: RowError[];
}

type ModalState = "idle" | "upload" | "preview" | "importing" | "done";

interface ExportFilter {
  category: string;
  technology: string;
}

interface BulkImportExportProps {
  activeFilters?: ExportFilter; // Passed in from parent table filters
  onImportSuccess?: () => void; // Callback to refresh the product list
}

// ─── Required CSV columns (all others are optional) ──────────────────────────
const REQUIRED_FIELDS = ["technical_name", "display_name", "category"] as const;
const VALID_CATEGORIES = ["camera", "recorder", "accessory", "cable", "network"];
const VALID_TECHNOLOGIES = ["HD", "IP", "Common", "WiFi", "4G"];

// ─── Validation logic ─────────────────────────────────────────────────────────
function validateRow(row: ParsedRow, index: number): RowError[] {
  const errs: RowError[] = [];
  const rowNum = index + 2; // 1-indexed + header row

  for (const field of REQUIRED_FIELDS) {
    if (!row[field] || String(row[field]).trim() === "") {
      errs.push({ row: rowNum, field, message: `"${field}" is required` });
    }
  }

  if (row.category && !VALID_CATEGORIES.includes(String(row.category))) {
    errs.push({
      row: rowNum,
      field: "category",
      message: `Invalid category "${row.category}". Must be one of: ${VALID_CATEGORIES.join(", ")}`,
    });
  }

  if (row.technology && !VALID_TECHNOLOGIES.includes(String(row.technology))) {
    errs.push({
      row: rowNum,
      field: "technology",
      message: `Invalid technology "${row.technology}". Must be one of: ${VALID_TECHNOLOGIES.join(", ")}`,
    });
  }

  if (row.base_cost !== undefined && row.base_cost !== "") {
    if (isNaN(Number(row.base_cost))) {
      errs.push({ row: rowNum, field: "base_cost", message: `base_cost must be a number` });
    }
  }

  if (row.margin_percentage !== undefined && row.margin_percentage !== "") {
    if (isNaN(Number(row.margin_percentage))) {
      errs.push({ row: rowNum, field: "margin_percentage", message: `margin_percentage must be a number` });
    }
  }

  return errs;
}

// ─── Component ────────────────────────────────────────────────────────────────
export function BulkImportExport({ activeFilters, onImportSuccess }: BulkImportExportProps) {
  const [modalState, setModalState] = useState<ModalState>("idle");
  const [isDragging, setIsDragging] = useState(false);
  const [fileName, setFileName] = useState("");
  const [preview, setPreview] = useState<PreviewResult | null>(null);
  const [importResult, setImportResult] = useState<{ created: number; updated: number } | null>(null);
  const [showExportDropdown, setShowExportDropdown] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  // ─── Export ────────────────────────────────────────────────────────────────
  const handleExport = useCallback(
    (useFilters: boolean) => {
      setShowExportDropdown(false);
      const params = new URLSearchParams();
      if (useFilters && activeFilters) {
        if (activeFilters.category) params.set("category", activeFilters.category);
        if (activeFilters.technology) params.set("technology", activeFilters.technology);
      }
      const url = `/api/admin/products/export${params.toString() ? `?${params}` : ""}`;
      // Trigger download by opening the URL
      const a = document.createElement("a");
      a.href = url;
      a.download = "";
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      toast.success("CSV export started — check your downloads.");
    },
    [activeFilters]
  );

  // ─── File parsing ──────────────────────────────────────────────────────────
  const parseFile = useCallback((file: File) => {
    if (!file.name.endsWith(".csv")) {
      toast.error("Only .csv files are accepted.");
      return;
    }
    setFileName(file.name);
    setModalState("upload"); // show spinner briefly while parsing

    Papa.parse<ParsedRow>(file, {
      header: true,
      skipEmptyLines: true,
      dynamicTyping: true, // Converts strings like "5" or "true" to proper JS types
      complete: (results) => {
        const rows = results.data as ParsedRow[];
        const toCreate: ParsedRow[] = [];
        const toUpdate: ParsedRow[] = [];
        const errors: RowError[] = [];

        rows.forEach((row, i) => {
          const rowErrors = validateRow(row, i);
          if (rowErrors.length > 0) {
            errors.push(...rowErrors);
          } else if (!row.id || String(row.id).trim() === "") {
            toCreate.push(row);
          } else {
            toUpdate.push(row);
          }
        });

        setPreview({ toCreate, toUpdate, errors });
        setModalState("preview");
      },
      error: (err) => {
        toast.error("Failed to parse CSV: " + err.message);
        setModalState("upload");
      },
    });
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) parseFile(file);
    e.target.value = "";
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) parseFile(file);
  };

  // ─── Execute import ────────────────────────────────────────────────────────
  const handleConfirmImport = async () => {
    if (!preview) return;
    const allRows = [...preview.toCreate, ...preview.toUpdate];
    setModalState("importing");

    try {
      const res = await fetch("/api/admin/products/import", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ products: allRows }),
      });
      const data = await res.json();
      if (!data.success) throw new Error(data.error);

      setImportResult({ created: data.created, updated: data.updated });
      setModalState("done");
      onImportSuccess?.();
    } catch (err: any) {
      toast.error(err.message || "Import failed. Please try again.");
      setModalState("preview");
    }
  };

  // ─── Reset ─────────────────────────────────────────────────────────────────
  const handleClose = () => {
    setModalState("idle");
    setPreview(null);
    setFileName("");
    setImportResult(null);
  };

  const hasActiveFilters = !!(activeFilters?.category || activeFilters?.technology);

  // ─── Render ────────────────────────────────────────────────────────────────
  return (
    <>
      {/* ── Action Buttons ────────────────────────────────────────────────── */}
      <div className="flex items-center gap-3">

        {/* Export Dropdown */}
        <div className="relative">
          <button
            id="btn-export-csv"
            onClick={() => setShowExportDropdown(!showExportDropdown)}
            className="flex items-center gap-2 px-5 py-3 bg-white dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 text-zinc-700 dark:text-zinc-200 rounded-xl text-[11px] font-black uppercase tracking-widest hover:bg-zinc-50 dark:hover:bg-zinc-700 transition-all shadow-sm active:scale-95 group whitespace-nowrap"
          >
            <FileDown className="w-4 h-4 text-emerald-500" />
            Export CSV
            <ChevronDown className={`w-3.5 h-3.5 text-zinc-400 transition-transform duration-200 ${showExportDropdown ? "rotate-180" : ""}`} />
          </button>

          {showExportDropdown && (
            <>
              {/* backdrop */}
              <div className="fixed inset-0 z-40" onClick={() => setShowExportDropdown(false)} />
              <div className="absolute right-0 top-full mt-2 z-50 bg-white dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-2xl shadow-md shadow-zinc-900/10 dark:shadow-black/40 overflow-hidden w-64 animate-in fade-in slide-in-from-top-2 duration-200">
                <button
                  id="btn-export-all"
                  onClick={() => handleExport(false)}
                  className="w-full flex items-start gap-3 px-5 py-4 hover:bg-zinc-50 dark:hover:bg-zinc-700/50 transition-colors text-left"
                >
                  <Download className="w-4 h-4 text-zinc-400 mt-0.5 shrink-0" />
                  <div>
                    <p className="text-xs font-black text-zinc-800 dark:text-white uppercase tracking-wider">Export All Products</p>
                    <p className="text-[10px] text-zinc-400 mt-0.5">Download the full product catalog</p>
                  </div>
                </button>
                {hasActiveFilters && (
                  <>
                    <div className="h-px bg-zinc-100 dark:bg-zinc-700 mx-4" />
                    <button
                      id="btn-export-filtered"
                      onClick={() => handleExport(true)}
                      className="w-full flex items-start gap-3 px-5 py-4 hover:bg-zinc-50 dark:hover:bg-zinc-700/50 transition-colors text-left"
                    >
                      <Filter className="w-4 h-4 text-blue-500 mt-0.5 shrink-0" />
                      <div>
                        <p className="text-xs font-black text-blue-600 dark:text-blue-400 uppercase tracking-wider">Export Filtered View</p>
                        <p className="text-[10px] text-zinc-400 mt-0.5 leading-tight">
                          {[activeFilters?.category, activeFilters?.technology].filter(Boolean).join(" · ")}
                        </p>
                      </div>
                    </button>
                  </>
                )}
                <div className="px-5 py-3 bg-zinc-50 dark:bg-zinc-900 border-t border-zinc-100 dark:border-zinc-700">
                  <p className="text-[10px] text-zinc-400 leading-relaxed">
                    The CSV template can also be re-imported with edits or new rows added.
                  </p>
                </div>
              </div>
            </>
          )}
        </div>

        {/* Import Button */}
        <button
          id="btn-import-csv"
          onClick={() => setModalState("upload")}
          className="flex items-center gap-2 px-5 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl text-[11px] font-black uppercase tracking-widest transition-all shadow-lg shadow-blue-600/20 active:scale-95 group whitespace-nowrap"
        >
          <Upload className="w-4 h-4" />
          Import CSV
        </button>
      </div>

      {/* ── Modal ─────────────────────────────────────────────────────────── */}
      {modalState !== "idle" && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-zinc-900 dark:bg-black animate-in fade-in duration-200">
          <div className="bg-white dark:bg-zinc-900 rounded-2xl shadow-[0_40px_80px_rgba(0,0,0,0.12)] dark:shadow-black/60 w-full max-w-2xl border border-zinc-200/50 dark:border-zinc-800 overflow-hidden flex flex-col animate-in zoom-in-95 duration-300">

            {/* Modal Header */}
            <div className="flex items-center justify-between px-8 py-6 border-b border-zinc-100 dark:border-zinc-800">
              <div className="flex items-center gap-4">
                <div className={`w-11 h-11 rounded-2xl flex items-center justify-center ${modalState === "done" ? "bg-emerald-100 dark:bg-emerald-500/10" : "bg-blue-100 dark:bg-blue-500/10"}`}>
                  {modalState === "done"
                    ? <CheckCircle2 className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
                    : <Upload className="w-5 h-5 text-blue-600 dark:text-blue-400" />}
                </div>
                <div>
                  <h2 className="text-base font-black text-zinc-900 dark:text-white tracking-tight">
                    {modalState === "upload" && "Import Products via CSV"}
                    {modalState === "preview" && "Review Import Changes"}
                    {modalState === "importing" && "Processing Import…"}
                    {modalState === "done" && "Import Complete"}
                  </h2>
                  <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest mt-0.5">
                    {modalState === "preview" && fileName}
