                    </div>
                    <p className="text-3xl font-black text-emerald-700 dark:text-emerald-300 tabular-nums">{preview.toCreate.length}</p>
                    <p className="text-[10px] text-emerald-600/60 dark:text-emerald-400/60 mt-0.5">products to create</p>
                  </div>
                  <div className="bg-blue-50 dark:bg-blue-500/10 rounded-2xl p-4 border border-blue-100 dark:border-blue-500/20">
                    <div className="flex items-center gap-2 mb-1">
                      <RefreshCcw className="w-4 h-4 text-blue-600 dark:text-blue-400" />
                      <p className="text-[10px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-widest">Update</p>
                    </div>
                    <p className="text-3xl font-black text-blue-700 dark:text-blue-300 tabular-nums">{preview.toUpdate.length}</p>
                    <p className="text-[10px] text-blue-600/60 dark:text-blue-400/60 mt-0.5">products to update</p>
                  </div>
                  <div className={`rounded-2xl p-4 border ${preview.errors.length > 0 ? "bg-red-50 dark:bg-red-500/10 border-red-100 dark:border-red-500/20" : "bg-zinc-50 dark:bg-zinc-800/50 border-zinc-100 dark:border-zinc-700"}`}>
                    <div className="flex items-center gap-2 mb-1">
                      <AlertCircle className={`w-4 h-4 ${preview.errors.length > 0 ? "text-red-500" : "text-zinc-400"}`} />
                      <p className={`text-[10px] font-black uppercase tracking-widest ${preview.errors.length > 0 ? "text-red-500" : "text-zinc-400"}`}>Errors</p>
                    </div>
                    <p className={`text-3xl font-black tabular-nums ${preview.errors.length > 0 ? "text-red-600 dark:text-red-400" : "text-zinc-300 dark:text-zinc-600"}`}>{preview.errors.length}</p>
                    <p className={`text-[10px] mt-0.5 ${preview.errors.length > 0 ? "text-red-500/60" : "text-zinc-400"}`}>rows with issues</p>
                  </div>
                </div>

                {/* Error table */}
                {preview.errors.length > 0 && (
                  <div className="rounded-2xl border border-red-100 dark:border-red-500/20 overflow-hidden">
                    <div className="bg-red-50 dark:bg-red-500/10 px-5 py-3 border-b border-red-100 dark:border-red-500/20">
                      <p className="text-[10px] font-black text-red-600 dark:text-red-400 uppercase tracking-widest">
                        ⚠ Rows with Errors — Fix your CSV and re-upload
                      </p>
                    </div>
                    <div className="max-h-48 overflow-y-auto scrollbar-none">
                      <table className="w-full text-xs">
                        <thead className="bg-zinc-50 dark:bg-zinc-800">
                          <tr>
                            <th className="text-left px-5 py-2 font-black text-zinc-400 uppercase tracking-widest text-[10px]">Row</th>
                            <th className="text-left px-5 py-2 font-black text-zinc-400 uppercase tracking-widest text-[10px]">Field</th>
                            <th className="text-left px-5 py-2 font-black text-zinc-400 uppercase tracking-widest text-[10px]">Issue</th>
                          </tr>
                        </thead>
                        <tbody>
                          {preview.errors.map((err, i) => (
                            <tr key={i} className="border-t border-zinc-100 dark:border-zinc-800">
                              <td className="px-5 py-2.5 font-mono font-bold text-red-500">#{err.row}</td>
                              <td className="px-5 py-2.5 font-mono text-zinc-600 dark:text-zinc-300">{err.field}</td>
                              <td className="px-5 py-2.5 text-zinc-500 dark:text-zinc-400">{err.message}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </div>
                )}

                {/* Valid rows preview */}
                {(preview.toCreate.length > 0 || preview.toUpdate.length > 0) && (
                  <div className="rounded-2xl border border-zinc-100 dark:border-zinc-800 overflow-hidden">
                    <div className="bg-zinc-50 dark:bg-zinc-800/60 px-5 py-3 border-b border-zinc-100 dark:border-zinc-800">
                      <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Valid Rows Preview (first 10)</p>
                    </div>
                    <div className="max-h-44 overflow-y-auto scrollbar-none">
                      <table className="w-full text-xs">
                        <thead className="bg-white dark:bg-zinc-900 sticky top-0">
                          <tr>
                            <th className="text-left px-5 py-2 font-black text-zinc-400 text-[10px] uppercase tracking-widest">Action</th>
                            <th className="text-left px-5 py-2 font-black text-zinc-400 text-[10px] uppercase tracking-widest">display_name</th>
                            <th className="text-left px-5 py-2 font-black text-zinc-400 text-[10px] uppercase tracking-widest">category</th>
                            <th className="text-left px-5 py-2 font-black text-zinc-400 text-[10px] uppercase tracking-widest">cost</th>
                          </tr>
                        </thead>
                        <tbody>
                          {[...preview.toCreate.slice(0, 10), ...preview.toUpdate.slice(0, Math.max(0, 10 - preview.toCreate.length))].map((row, i) => {
                            const isNew = !row.id || row.id.trim() === "";
                            return (
                              <tr key={i} className="border-t border-zinc-100 dark:border-zinc-800 hover:bg-zinc-50 dark:hover:bg-zinc-800/40 transition-colors">
                                <td className="px-5 py-2.5">
                                  <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${isNew ? "bg-emerald-100 dark:bg-emerald-500/20 text-emerald-600 dark:text-emerald-400" : "bg-blue-100 dark:bg-blue-500/20 text-blue-600 dark:text-blue-400"}`}>
                                    {isNew ? "CREATE" : "UPDATE"}
                                  </span>
                                </td>
                                <td className="px-5 py-2.5 font-semibold text-zinc-800 dark:text-zinc-200 max-w-[180px] truncate">{String(row.display_name || "")}</td>
                                <td className="px-5 py-2.5 text-zinc-500 dark:text-zinc-400">{String(row.category || "")}</td>
                                <td className="px-5 py-2.5 font-mono text-zinc-600 dark:text-zinc-300">₹{String(row.base_cost || "—")}</td>
                              </tr>
                            );
                          })}
                        </tbody>
                      </table>
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* ── State: Importing ─────────────────────────────────────────── */}
            {modalState === "importing" && (
              <div className="p-16 flex flex-col items-center gap-6">
                <div className="relative">
                  <div className="w-20 h-20 rounded-full border-4 border-blue-100 dark:border-blue-500/20" />
                  <div className="absolute inset-0 w-20 h-20 rounded-full border-4 border-t-blue-500 animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center">
                    <Upload className="w-7 h-7 text-blue-500" />
                  </div>
                </div>
                <div className="text-center">
                  <p className="text-sm font-black text-zinc-800 dark:text-white">Writing to Firestore…</p>
                  <p className="text-xs text-zinc-400 mt-1">This may take a moment for large catalogs</p>
                </div>
              </div>
            )}

            {/* ── State: Done ───────────────────────────────────────────────── */}
            {modalState === "done" && importResult && (
              <div className="p-10 flex flex-col items-center gap-6 text-center">
                <div className="w-20 h-20 rounded-full bg-emerald-100 dark:bg-emerald-500/20 flex items-center justify-center shadow-md shadow-emerald-500/10">
                  <CheckCircle2 className="w-10 h-10 text-emerald-500" />
                </div>
                <div>
                  <p className="text-lg font-black text-zinc-900 dark:text-white">Import Successful!</p>
                  <p className="text-sm text-zinc-400 mt-1">Your product catalog has been updated.</p>
                </div>
                <div className="flex items-center gap-6">
                  <div className="text-center">
                    <p className="text-3xl font-black text-emerald-600 dark:text-emerald-400 tabular-nums">{importResult.created}</p>
                    <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mt-1">Created</p>
                  </div>
                  <div className="w-px h-10 bg-zinc-200 dark:bg-zinc-700" />
                  <div className="text-center">
                    <p className="text-3xl font-black text-blue-600 dark:text-blue-400 tabular-nums">{importResult.updated}</p>
                    <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mt-1">Updated</p>
                  </div>
                </div>
              </div>
            )}

            {/* ── Modal Footer ─────────────────────────────────────────────── */}
            <div className="px-8 py-5 border-t border-zinc-100 dark:border-zinc-800 flex items-center justify-between bg-zinc-50/50 dark:bg-zinc-900">
              <button
                onClick={handleClose}
                disabled={modalState === "importing"}
                className="text-[11px] font-black uppercase tracking-widest text-zinc-400 hover:text-zinc-700 dark:hover:text-zinc-200 transition-colors disabled:opacity-30 px-2"
              >
                {modalState === "done" ? "Close" : "Cancel"}
              </button>

              {modalState === "preview" && preview && (
                <button
                  id="btn-confirm-import"
                  onClick={handleConfirmImport}
                  disabled={preview.toCreate.length === 0 && preview.toUpdate.length === 0}
                  className="flex items-center gap-2.5 px-7 py-3 bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-zinc-800 dark:hover:bg-zinc-100 transition-all shadow-md shadow-zinc-900/10 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed"
                >
                  Confirm & Import
                  <ArrowRight className="w-4 h-4" />
                </button>
              )}

              {modalState === "upload" && (
                <button
                  onClick={() => fileRef.current?.click()}
                  className="flex items-center gap-2.5 px-7 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all shadow-lg shadow-blue-600/20 active:scale-95"
                >
                  <Upload className="w-4 h-4" />
                  Choose File
                </button>
              )}

              {modalState === "done" && (
                <button
                  onClick={() => { handleClose(); }}
                  className="flex items-center gap-2.5 px-7 py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all shadow-lg shadow-emerald-600/20 active:scale-95"
                >
                  <CheckCircle2 className="w-4 h-4" />
                  Done
                </button>
              )}
            </div>
          </div>
        </div>
      )}
    </>
  );
}

"use client";

import { useState, useEffect } from "react";
import { ProductGroup } from "@/types";
import { ChevronDown, Plus, Loader2, FolderTree, X } from "lucide-react";
import { toast } from "sonner";

interface CategoryGroupSelectorProps {
  value: string | null; // Selected group ID
  onChange: (groupId: string | null, fullPath: string | null) => void;
  label?: string;
}

export function CategoryGroupSelector({ value, onChange, label = "Catalog Group" }: CategoryGroupSelectorProps) {
  const [groups, setGroups] = useState<ProductGroup[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState("");

  // Inline Creation State
  const [isCreating, setIsCreating] = useState(false);
  const [newGroupName, setNewGroupName] = useState("");
  const [newGroupParentId, setNewGroupParentId] = useState<string | "root">("root");
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    fetchGroups();
  }, []);

  const fetchGroups = async () => {
    try {
      const res = await fetch("/api/admin/product-groups");
      const data = await res.json();
      if (data.success) {
        setGroups(data.groups);
      }
    } catch (error) {
      console.error("Failed to load groups:", error);
    } finally {
      setIsLoading(false);
    }
  };

  const selectedGroup = groups.find(g => g.id === value);
  const filteredGroups = groups.filter(g => g.full_path.toLowerCase().includes(search.toLowerCase()));

  const handleCreateGroup = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newGroupName.trim()) return;

    try {
      setIsSaving(true);
      const res = await fetch("/api/admin/product-groups", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: newGroupName.trim(),
          parent_id: newGroupParentId === "root" ? null : newGroupParentId
        })
      });
      const data = await res.json();

      if (data.success) {
        setGroups(prev => [...prev, data.group].sort((a, b) => a.full_path.localeCompare(b.full_path)));
        onChange(data.group.id!, data.group.full_path);
        setIsCreating(false);
        setIsOpen(false);
        setNewGroupName("");
        toast.success(`Group "${data.group.name}" created`);
      } else {
        throw new Error(data.error);
      }
    } catch (error: any) {
      toast.error(error.message || "Failed to create group");
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="relative space-y-2.5">
      <label className="text-[10px] font-black text-zinc-500 dark:text-zinc-400 uppercase tracking-widest ml-1">{label}</label>

      {/* Trigger Button */}
      <div 
        onClick={() => !isLoading && setIsOpen(!isOpen)}
        className={`w-full flex items-center justify-between bg-zinc-50 dark:bg-zinc-950 border ${isOpen ? 'border-blue-500 ring-4 ring-blue-500/10' : 'border-zinc-200 dark:border-zinc-800'} rounded-2xl px-6 py-4 text-sm font-bold transition-all cursor-pointer dark:text-white`}
      >
        <div className="flex items-center gap-3 truncate">
          <FolderTree className="w-4 h-4 text-zinc-400 shrink-0" />
          <span className="truncate">
            {isLoading ? "Loading directory..." : selectedGroup ? selectedGroup.full_path : "Select Catalog Group..."}
          </span>
        </div>
        {isLoading ? <Loader2 className="w-4 h-4 animate-spin text-zinc-400" /> : <ChevronDown className={`w-4 h-4 text-zinc-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />}
      </div>

      {/* Dropdown Menu */}
      {isOpen && (
        <div className="absolute z-[110] top-full left-0 right-0 mt-2 bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl shadow-md overflow-hidden flex flex-col max-h-[400px]">

          {!isCreating ? (
            <>
              {/* Search Header */}
              <div className="p-3 border-b border-zinc-100 dark:border-zinc-800">
                <input
                  type="text"
                  placeholder="Search paths..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  className="w-full bg-zinc-50 dark:bg-zinc-950 border border-zinc-200 dark:border-zinc-800 rounded-xl px-4 py-2.5 text-xs font-bold focus:outline-none dark:text-white"
                />
              </div>

              {/* Group List */}
              <div className="flex-1 overflow-y-auto py-2">
                {filteredGroups.length === 0 ? (
                  <div className="px-6 py-8 text-center text-zinc-400 text-xs font-bold">
                    No groups found matching "{search}"
                  </div>
                ) : (
                  filteredGroups.map(group => {
                    // Calculate visual indentation based on path depth
                    const depth = group.full_path.split("/").length - 1;
                    return (
                      <div 
                        key={group.id}
                        onClick={() => {
                          onChange(group.id!, group.full_path);
                          setIsOpen(false);
                        }}
                        className={`flex items-center px-4 py-2.5 mx-2 rounded-xl cursor-pointer hover:bg-blue-50 dark:hover:bg-blue-900/20 transition-colors ${value === group.id ? 'bg-blue-50/50 dark:bg-blue-900/10 text-blue-600 dark:text-blue-400' : 'text-zinc-700 dark:text-zinc-300'}`}
                      >
                        <div style={{ width: depth * 16 }} className="shrink-0" />
                        {depth > 0 && <div className="w-3 h-3 border-l-2 border-b-2 border-zinc-300 dark:border-zinc-700 rounded-bl mr-3 shrink-0" />}
                        {!depth && <FolderTree className="w-3.5 h-3.5 mr-3 shrink-0 text-zinc-400" />}
                        <span className="text-xs font-bold truncate">{group.name}</span>
                      </div>
                    );
                  })
                )}
              </div>

              {/* Create New Action */}
              <div className="p-3 border-t border-zinc-100 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-900">
                <button
                  type="button"
                  onClick={() => setIsCreating(true)}
                  className="w-full flex items-center justify-center gap-2 py-2.5 bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-zinc-800 dark:hover:bg-zinc-100 transition-colors"
                >
                  <Plus className="w-3 h-3" />
                  Create New Group
                </button>
              </div>
            </>
          ) : (
            /* Inline Create Form */
            <form onSubmit={handleCreateGroup} className="p-6 space-y-6">
              <div className="flex items-center justify-between">
                <h4 className="text-xs font-black uppercase tracking-widest text-zinc-900 dark:text-white">New Catalog Group</h4>
                <button type="button" onClick={() => setIsCreating(false)} className="text-zinc-400 hover:text-red-500">
                  <X className="w-4 h-4" />
                </button>
              </div>

              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-zinc-500 uppercase">Under Parent Group (Optional)</label>
                  <select 
                    value={newGroupParentId}
                    onChange={e => setNewGroupParentId(e.target.value)}
                    className="w-full bg-zinc-50 dark:bg-zinc-950 border border-zinc-200 dark:border-zinc-800 rounded-xl px-4 py-2.5 text-xs font-bold focus:outline-none dark:text-white"
                  >
                    <option value="root">-- Top Level (No Parent) --</option>
                    {groups.map(g => (
                      <option key={g.id} value={g.id}>{g.full_path}</option>
                    ))}
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-zinc-500 uppercase">Group Name</label>
                  <input
                    autoFocus
                    type="text"
                    value={newGroupName}
                    onChange={e => setNewGroupName(e.target.value)}
                    placeholder="e.g. 5MP ColorVu"
                    className="w-full bg-zinc-50 dark:bg-zinc-950 border border-zinc-200 dark:border-zinc-800 rounded-xl px-4 py-2.5 text-sm font-bold focus:outline-none dark:text-white focus:border-blue-500"
                  />
                </div>
              </div>

              <div className="flex gap-3">
                <button
                  type="button"
                  onClick={() => setIsCreating(false)}
                  className="flex-1 py-3 text-[10px] font-black uppercase tracking-widest text-zinc-500 hover:bg-zinc-100 dark:hover:bg-zinc-800 rounded-xl transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={!newGroupName.trim() || isSaving}
                  className="flex-1 flex items-center justify-center gap-2 py-3 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white rounded-xl text-[10px] font-black uppercase tracking-widest transition-colors"
                >
                  {isSaving ? <Loader2 className="w-3 h-3 animate-spin" /> : <Plus className="w-3 h-3" />}
                  Create
                </button>
              </div>
            </form>
          )}

        </div>
      )}

      {/* Click outside overlay (simple hack since we don't have a useClickOutside hook) */}
      {isOpen && (
        <div className="fixed inset-0 z-[100]" onClick={() => setIsOpen(false)} />
      )}
    </div>
  );
}

