"use client";

import React, { useMemo, useState } from "react";
import { Info, IndianRupee, ShieldCheck } from "lucide-react";
import { calculatePricing } from "@/lib/pricing-engine";
import type { Product, Addon, AppSettings, AddonRuleResult } from "@/types";
import { SystemSummary } from "./SystemSummary";
import { X } from "lucide-react";

interface PriceRangeTickerProps {
  cameraCount: number;
  products: Product[];
  addons: Addon[];
  settings: AppSettings;
  cablingDone: boolean;
  promoterDiscount?: { percent: number; flat: number };
  evaluatedAddonRules: Record<string, AddonRuleResult>;
  activeOffer?: any;
  selection: any;
}

export function PriceRangeTicker({
  cameraCount,
  products,
  addons,
  settings,
  cablingDone,
  promoterDiscount,
  evaluatedAddonRules,
  activeOffer,
  selection
}: PriceRangeTickerProps) {
  const [modalData, setModalData] = useState<{ title: string; pricing: any } | null>(null);

  // Default to HD for absolute lowest, but respect selected tech if it's strictly IP
  const minTech = (selection.technology === "IP") ? "IP" : "HD";
  // Default to IP for absolute highest, but respect selected tech if it's strictly HD
  const maxTech = (selection.technology === "HD") ? "HD" : "IP";

  const { lowest, highest } = useMemo(() => {
    if (!products.length || !settings) return { lowest: null, highest: null };

    // Calculate absolute lowest (HD, Budget) ignoring all filters
    const lowestConfig = calculatePricing({
      selection: {
        camera_count: cameraCount,
        technology: minTech,
        plan_type: "budget",
        recording_days: 7,
        selected_addons: [],
        picture_quality: selection.picture_quality || "good",
        brand_preference: selection.brand_preference || "all",
        requested_features: selection.requested_features || [],
        max_budget: null,
        focus_point: "price",
        selected_camera_option: 1 // Lowest
      },
      products,
      addons,
      settings,
      cablingDone,
      referralDiscountPercent: promoterDiscount?.percent || 0,
      referralDiscountFlat: promoterDiscount?.flat || 0,
      evaluatedAddonRules,
      activeOffer
    });

    // Calculate absolute highest (IP, Premium) ignoring all filters
    const highestConfig = calculatePricing({
      selection: {
        camera_count: cameraCount,
        technology: maxTech,
        plan_type: "premium",
        recording_days: 30, // Maximize storage for highest quote
        selected_addons: [],
        picture_quality: selection.picture_quality || "crystal_clear",
        brand_preference: selection.brand_preference || "all",
        requested_features: selection.requested_features || [],
        max_budget: null,
        focus_point: "quality",
        selected_camera_option: 3 // Highest
      },
      products,
      addons,
      settings,
      cablingDone,
      referralDiscountPercent: promoterDiscount?.percent || 0,
      referralDiscountFlat: promoterDiscount?.flat || 0,
      evaluatedAddonRules,
      activeOffer
    });

    return { lowest: lowestConfig, highest: highestConfig };
  }, [cameraCount, products, addons, settings, cablingDone, promoterDiscount, evaluatedAddonRules, activeOffer, selection]);

  if (!lowest || !highest) return null;

  return (
    <>
      <div className="w-full bg-blue-50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-900/30 rounded-2xl p-4 flex flex-col sm:flex-row items-center justify-between gap-4 mt-6">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-blue-100 dark:bg-blue-900/40 flex items-center justify-center shrink-0">
            <Info className="w-5 h-5 text-blue-600 dark:text-blue-400" />
          </div>
          <div>
            <p className="text-sm font-semibold text-zinc-900 dark:text-white">
              Market Insight for {cameraCount} Cameras
            </p>
            <p className="text-xs font-medium text-zinc-500 dark:text-zinc-400">
              Explore the absolute lowest and highest possibilities for your current filters.
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button 
            onClick={() => setModalData({ title: `Absolute Lowest Configuration (${minTech})`, pricing: lowest })}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-xl hover:border-blue-500 dark:hover:border-blue-500 transition-colors group"
          >
            <span className="text-xs font-black text-zinc-500 uppercase tracking-wider group-hover:text-blue-600 transition-colors">Lowest</span>
            <span className="text-sm font-black text-zinc-900 dark:text-white flex items-center">
              <IndianRupee className="w-3.5 h-3.5 mr-0.5" />
              {lowest.total_payable.toLocaleString()}
            </span>
          </button>

          <span className="text-zinc-300 dark:text-zinc-700 font-light">—</span>

          <button 
            onClick={() => setModalData({ title: `Ultimate Premium Configuration (${maxTech})`, pricing: highest })}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-xl hover:border-amber-500 dark:hover:border-amber-500 transition-colors group"
          >
            <span className="text-xs font-black text-zinc-500 uppercase tracking-wider group-hover:text-amber-600 transition-colors">Highest</span>
            <span className="text-sm font-black text-zinc-900 dark:text-white flex items-center">
              <IndianRupee className="w-3.5 h-3.5 mr-0.5" />
              {highest.total_payable.toLocaleString()}
            </span>
          </button>
        </div>
      </div>

      {modalData && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="relative w-full max-w-3xl max-h-[85vh] overflow-y-auto bg-white dark:bg-zinc-900 rounded-3xl shadow-2xl p-6 sm:p-8">
            <button 
              onClick={() => setModalData(null)}
              className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center rounded-full bg-zinc-100 dark:bg-zinc-800 text-zinc-500 hover:text-zinc-900 dark:hover:text-white transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
            <div className="flex items-center gap-3 text-xl font-black uppercase tracking-tight mb-6">
              <ShieldCheck className="w-6 h-6 text-blue-500" />
              {modalData.title}
            </div>
            <SystemSummary items={modalData.pricing.items} addons={modalData.pricing.addons} />
          </div>
        </div>
      )}
    </>
  );
}

"use client";

import { useState } from "react";
import { FileText, ArrowRight, Copy, Check, MessageSquare, User, Phone, MapPin, Home, Camera } from "lucide-react";

const PROPERTY_TYPES = [
  { value: "home",      label: "Home / Flat" },
  { value: "bungalow",  label: "Bungalow / Villa" },
  { value: "office",    label: "Office / Shop" },
  { value: "warehouse", label: "Warehouse / Factory" },
];

export default function WalkInQuoteClient() {
  const [form, setForm] = useState({
    name: "",
    mobile: "",
    city: "Jaipur",
    property_type: "home",
    camera_count: 4,
  });
  const [loading, setLoading] = useState(false);
  const [quoteUrl, setQuoteUrl] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setQuoteUrl(null);

    try {
      const res = await fetch("/api/leads", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          customer_name:     form.name,
          mobile_number:     form.mobile,
          property_type:     form.property_type,
          technology_choice: "HD",
          cabling_done:      false,
          detected_city:     form.city,
          source:            "walk_in",
          wizard_answers: {
            camera_count:  form.camera_count,
            property_type: form.property_type,
          },
        }),
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data?.error || "Failed to create lead");
      }

      const { leadId } = await res.json();
      const url = `${window.location.origin}/quote/${leadId}`;
      setQuoteUrl(url);
    } catch (err: any) {
      setError(err.message || "Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  const handleCopy = async () => {
    if (!quoteUrl) return;
    await navigator.clipboard.writeText(quoteUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleWhatsApp = () => {
    if (!quoteUrl) return;
    const msg = encodeURIComponent(
      `Namaste ${form.name} ji! 🙏\n\nYour personalised CCTV quotation is ready.\n\n👉 ${quoteUrl}\n\nReview karo aur confirm karo — hum installation plan karenge.\n\n- TEAM CCTV`
    );
    window.open(`https://wa.me/91${form.mobile}?text=${msg}`, "_blank");
  };

  const set = (k: string, v: string | number) => setForm(f => ({ ...f, [k]: v }));

  return (
    <div className="max-w-2xl space-y-8 animate-in fade-in duration-500">
      {!quoteUrl ? (
        <form onSubmit={handleSubmit} className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-3xl p-8 space-y-6 shadow-sm">
          <div>
            <h2 className="text-xl font-black text-white mb-1">Walk-In Customer Details</h2>
            <p className="text-sm text-zinc-400">Fill in the customer's basic info to generate an instant quotation link.</p>
          </div>

          {/* Name */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-1.5">
              <User className="w-3 h-3" /> Customer Name
            </label>
            <input
              required
              value={form.name}
              onChange={e => set("name", e.target.value)}
              placeholder="e.g. Ramesh Sharma"
              className="w-full px-4 py-3 rounded-2xl border border-white/10 bg-[#030303] text-white text-sm font-medium focus:outline-none focus:border-blue-500/50 transition-all placeholder:text-zinc-500"
            />
          </div>

          {/* Mobile */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-1.5">
              <Phone className="w-3 h-3" /> Mobile Number
            </label>
            <input
              required
              type="tel"
              pattern="[0-9]{10}"
              value={form.mobile}
              onChange={e => set("mobile", e.target.value)}
              placeholder="10-digit mobile number"
              className="w-full px-4 py-3 rounded-2xl border border-white/10 bg-[#030303] text-white text-sm font-medium focus:outline-none focus:border-blue-500/50 transition-all placeholder:text-zinc-500"
            />
          </div>

          {/* City + Property Type — side by side */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-1.5">
                <MapPin className="w-3 h-3" /> City
              </label>
              <input
                required
                value={form.city}
                onChange={e => set("city", e.target.value)}
                placeholder="e.g. Jaipur"
                className="w-full px-4 py-3 rounded-2xl border border-white/10 bg-[#030303] text-white text-sm font-medium focus:outline-none focus:border-blue-500/50 transition-all placeholder:text-zinc-500"
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-1.5">
                <Home className="w-3 h-3" /> Property Type
              </label>
              <select
                value={form.property_type}
                onChange={e => set("property_type", e.target.value)}
                className="w-full px-4 py-3 rounded-2xl border border-white/10 bg-[#030303] text-white text-sm font-medium focus:outline-none focus:border-blue-500/50 transition-all"
              >
                {PROPERTY_TYPES.map(p => <option key={p.value} value={p.value}>{p.label}</option>)}
              </select>
            </div>
          </div>

          {/* Camera Count */}
          <div className="space-y-2">
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-1.5">
              <Camera className="w-3 h-3" /> Camera Count — <span className="text-blue-500">{form.camera_count} cameras</span>
            </label>
            <input
              type="range"
              min={1} max={16} step={1}
              value={form.camera_count}
              onChange={e => set("camera_count", parseInt(e.target.value))}
              className="w-full accent-blue-500"
            />
            <div className="flex justify-between text-[9px] font-bold text-zinc-400">
              {[1,2,4,6,8,12,16].map(n => <span key={n}>{n}</span>)}
            </div>
          </div>

          {error && (
            <div className="p-3 rounded-2xl bg-red-50 dark:bg-red-500/10 border border-red-200 dark:border-red-500/20 text-red-700 dark:text-red-400 text-sm font-bold">
              ⚠ {error}
            </div>
          )}

          <button
            type="submit"
            disabled={loading}
            className="w-full flex items-center justify-center gap-3 bg-amber-500 hover:bg-amber-600 disabled:bg-amber-300 text-white px-8 py-4 rounded-2xl font-black uppercase tracking-widest transition-all shadow-lg shadow-amber-500/30 hover:-translate-y-0.5 active:translate-y-0 group"
          >
            {loading ? "Generating…" : "Generate Quote Link"}
            {!loading && <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />}
          </button>
        </form>
      ) : (
        <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-3xl p-8 space-y-6 shadow-sm animate-in fade-in zoom-in-95 duration-500">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-2xl bg-emerald-500 flex items-center justify-center shadow-[0_0_20px_rgba(16,185,129,0.3)]">
              <Check className="w-7 h-7 text-white" />
            </div>
            <div>
              <h2 className="text-xl font-black text-white">Quote Ready!</h2>
              <p className="text-sm text-zinc-400">Share this link with <span className="font-bold text-white">{form.name}</span></p>
            </div>
          </div>

          <div className="flex items-center gap-2 p-4 rounded-2xl bg-[#030303] border border-white/10">
            <p className="text-sm font-mono text-zinc-300 flex-1 truncate">{quoteUrl}</p>
            <button onClick={handleCopy} className={`p-2 rounded-xl transition-all ${copied ? "bg-emerald-500 text-white" : "bg-white/10 text-white hover:bg-blue-500 hover:text-white"}`}>
              {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
            </button>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <button
              onClick={handleWhatsApp}
              className="flex items-center justify-center gap-2 px-6 py-3.5 bg-emerald-500 hover:bg-emerald-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest transition-all shadow-[0_0_15px_rgba(16,185,129,0.3)]"
            >
              <MessageSquare className="w-4 h-4" /> Send on WhatsApp
            </button>
            <button
              onClick={() => { setQuoteUrl(null); setForm({ name: "", mobile: "", city: "Jaipur", property_type: "home", camera_count: 4 }); }}
              className="flex items-center justify-center gap-2 px-6 py-3.5 bg-white/5 hover:bg-white/10 text-white border border-white/10 rounded-2xl font-black text-sm uppercase tracking-widest transition-all"
            >
              New Quote
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { ShieldCheck, Phone, CheckCircle2, Loader2, ArrowRight, X, Sparkles } from "lucide-react";

interface PhoneCaptureModalProps {
  pincode: string;
  onClose: () => void;
}

export function PhoneCaptureModal({ pincode, onClose }: PhoneCaptureModalProps) {
  const [step, setStep] = useState<"phone" | "otp" | "success">("phone");
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [countdown, setCountdown] = useState(0);
  const [canResend, setCanResend] = useState(false);

  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);
  const abortControllerRef = useRef<AbortController | null>(null);

  // 1. Verification Timer
  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (countdown > 0) {
      timer = setTimeout(() => setCountdown(countdown - 1), 1000);
    } else if (countdown === 0 && step === "otp") {
      setCanResend(true);
    }
    return () => clearTimeout(timer);
  }, [countdown, step]);

  // 2. WebOTP auto-fill integration
  useEffect(() => {
    if (step !== "otp") return;

    // Check if WebOTP API is supported
    if (typeof window !== "undefined" && "OTPCredential" in window) {
      try {
        // Create an abort controller to prevent hanging background listeners
        const ac = new AbortController();
        abortControllerRef.current = ac;

        navigator.credentials
          .get({
            otp: { transport: ["sms"] },
            signal: ac.signal,
          } as any)
          .then((content) => {
            const credential = content as any;
            if (credential && credential.code) {
              const code = credential.code.replace(/\D/g, "");
              if (code.length === 6) {
                const otpArray = code.split("");
                setOtp(otpArray);
                // Trigger auto-submit with a small dynamic micro-delay
                setTimeout(() => handleAutoSubmit(otpArray), 400);
              }
            }
          })
          .catch((err) => {
            console.log("[WebOTP Debug]:", err);
          });
      } catch (e) {
        console.warn("[WebOTP Init Error]:", e);
      }
    }

    return () => {
      // Abort background credential listener if modal closes or step changes
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, [step]);

  // Sends the OTP via the mock endpoint
  const sendOtpCode = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setError("");

    if (!/^[6-9]\d{9}$/.test(mobile)) {
      return setError("Enter a valid 10-digit Indian mobile number (starts with 6–9).");
    }

    setLoading(true);
    try {
      const res = await fetch("/api/send-otp", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ mobile }),
      });
      const data = await res.json();

      if (!res.ok) throw new Error(data.error || "Failed to transmit verification code.");

      // In development, alert the code for local convenience
      if (process.env.NODE_ENV === "development" && data.devCode) {
        console.log(`%c[DEV MOCK OTP]: ${data.devCode}`, "color: #10B981; font-weight: bold; font-size: 14px;");
      }

      setStep("otp");
      setCountdown(30);
      setCanResend(false);
    } catch (err: any) {
      setError(err.message || "Failed to send code. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleOtpChange = (value: string, index: number) => {
    if (isNaN(Number(value))) return;
    const newOtp = [...otp];
    newOtp[index] = value.substring(value.length - 1);
    setOtp(newOtp);

    // Auto-focus next input
    if (value && index < 5) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>, index: number) => {
    if (e.key === "Backspace" && !otp[index] && index > 0) {
      inputRefs.current[index - 1]?.focus();
    }
  };

  // Handles manual submission
  const handleVerifyAndSave = async (e: React.FormEvent) => {
    e.preventDefault();
    const fullOtp = otp.join("");
    if (fullOtp.length < 6) return setError("Please enter the complete 6-digit code.");

    setLoading(true);
    setError("");

    try {
      const res = await fetch("/api/interest-leads", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          pincode,
          mobile,
          code: fullOtp,
        }),
      });
      const data = await res.json();

      if (!res.ok) throw new Error(data.error || "Verification failed.");

      setStep("success");
    } catch (err: any) {
      setOtp(["", "", "", "", "", ""]);
      inputRefs.current[0]?.focus();
      setError(err.message || "Incorrect code. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  // Handles WebOTP automatic submit without manual button clicks
  const handleAutoSubmit = async (otpArray: string[]) => {
    const fullOtp = otpArray.join("");
    setLoading(true);
    setError("");
    try {
      const res = await fetch("/api/interest-leads", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          pincode,
          mobile,
          code: fullOtp,
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Verification failed.");
      setStep("success");
    } catch (err: any) {
      setOtp(["", "", "", "", "", ""]);
      setError(err.message || "Auto-fill verification failed. Please enter code manually.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[300] flex items-center justify-center p-3 sm:p-4 bg-zinc-950/40 dark:bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white dark:bg-zinc-900 border border-zinc-200/50 dark:border-zinc-800/80 shadow-2xl rounded-[32px] w-full max-w-md p-6 sm:p-8 relative overflow-hidden transition-all animate-in zoom-in-95 duration-300">

        {/* Close Button */}
        <button
          onClick={onClose}
          className="absolute right-4 top-4 p-1.5 rounded-full text-zinc-400 hover:text-zinc-900 dark:hover:text-white hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors"
          aria-label="Close modal"
        >
          <X className="w-5 h-5" />
        </button>

        {/* Step 1: Phone Capture */}
        {step === "phone" && (
          <form onSubmit={sendOtpCode} className="space-y-6">
            <div className="text-center">
              <div className="inline-flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 font-bold px-4.5 py-1.5 rounded-full text-[10px] uppercase tracking-widest mb-4 border border-indigo-100 dark:border-indigo-800">
                <Sparkles className="w-3.5 h-3.5" />
                Service Expansion
              </div>
              <h3 className="text-2xl sm:text-3xl font-black text-zinc-900 dark:text-white tracking-tighter leading-none mb-3">
                Unlock Installation
              </h3>
              <p className="text-zinc-500 dark:text-zinc-400 font-medium text-xs sm:text-sm">
                Enter your mobile number to authorize the lookup for PIN-code <strong className="text-zinc-900 dark:text-white font-bold">{pincode}</strong>.
              </p>
            </div>

            {error && (
              <div className="bg-red-500 text-white px-4 py-3 rounded-2xl text-xs font-bold text-center flex items-center gap-2.5">
                <ShieldCheck className="w-4 h-4 shrink-0" />
                <span>{error}</span>
              </div>
            )}

            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-zinc-400 dark:text-zinc-500 uppercase tracking-widest ml-1">
                Mobile Number
              </label>
              <div className="relative">
